export type Item = { kind: "sword" | "amulet" };

export type QuoteStep = { kind: "quote"; items: Item[] };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

export type ScenarioResult = {
  results: unknown[];
};

const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
  sword: 100,
  amulet: 60,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const item = step.items[0];
    const basePremium = BASE_PREMIUM_BY_ITEM[item.kind];
    const withSurcharge = basePremium * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
    const premium = withSurcharge + PROCESSING_FEE;
    return { kind: "quote", premium };
  });
  return { results };
}

